INSERT INTO `plugin` VALUES (0,'Plugin System','The global configuration for all TMX plugins','4.0'),(1,'CARMACloud','CARMA cloud plugin for making websocket connection with CARMA cloud .','7.6.0'),(2,'CARMAStreetsPlugin','Plugin to communicate with CARMA Streets via Apache Kafka','7.6.0'),(3,'CDASimAdapter','CDASim Adapter is the V2X-Hub plugin that facilitates the connection between the CDASim simulation environment and V2X-Hub and CARMA Streets.','7.6.0'),(4,'CommandPlugin','Listens for websocket connections from the TMX admin portal and processes commands','7.6.0'),(5,'CSW','Provides Curve Speed Warning (CSW).','7.6.0'),(6,'DynamicMessageSign','Provides communication to a dynamic message sign.','7.6.0'),(7,'ERVCloudForwarding','ERV (Emergency Response Vehicle) cloud plugin for making websocket connection with CARMA cloud, and forward ERV BSM to CARMA cloud.','7.6.0'),(8,'ImmediateForward','Plugin that listens for TMX messages and forwards them to the V2X Radio (i.e. the RSU).','7.6.0'),(9,'Location','Plugin used to send out Location Messages using data from GPSD','7.6.0'),(10,'MAP','Plugin that reads intersection geometry from a configuration file and publishes a J2735 MAP message.','7.6.0'),(11,'MessageLoggerPlugin','Listens for J2735 messages and logs them in a file in JSON format.','7.6.0'),(12,'MessageReceiver','Plugin to receive messages from an external V2X radio or other source','7.6.0'),(13,'ODEForwardPlugin','Listens for J2735 messages and realtime forwards them to ODE.','7.6.0'),(14,'Pedestrian','Pedestrian plugin for the IVP system.','7.6.0'),(15,'PortDrayagePlugin','PortDrayagePlugin for sending freight trucks automated actions in a port.','7.6.0'),(16,'Preemption','Preemption plugin for the IVP system.','7.6.0'),(17,'RTCM','Plugin to listen for RTCM messages from an NTRIP caster and route those messages over a V2X radio','7.6.0'),(18,'SPAT','Plugin that reads PTLM data from a configuration file, receives live data from the signal controller, and publishes a J2735 SPAT message.','7.6.0'),(19,'TIM','Provides Traveller Information Message (TIM).','7.6.0'),(20,'ivpcore.PluginMonitor','Core element that is responsible for starting/stopping installed plugins and monitoring the status of the plugins','3.2.0'),(21,'ivpcore.MessageProfiler','Core element that is responsible for profiling the statistics of received messages','3.2.0'),(22,'ivpcore.HistoryManager','Core element that is responsible for purging old log and history data','3.2.0'),(23,'RSUHealthMonitor','Monitor RSU health status','7.6.0'),(24,'TelematicBridge','Plugin that listens for TMX messages and forward them to the Telematic cloud services.','7.6.0');
